-- Reemplaza la plantilla del cronograma por las tareas reales del archivo Recursos/Cronograma V1.xlsx.
-- Incluye backup de tareas, vinculos y entregables antes del reemplazo.

create table if not exists public.tasks_backup_cronograma_v1_20260511 as
select now() as backed_up_at, * from public.tasks;

create table if not exists public.task_deliverables_backup_cronograma_v1_20260511 as
select now() as backed_up_at, * from public.task_deliverables;

create table if not exists public.deliverables_backup_cronograma_v1_20260511 as
select now() as backed_up_at, * from public.deliverables;

delete from public.tasks;

