    phase_code text,
    title text,
    description text,
    item_type text,
    status text,
    priority text,
    owner_name text,
    start_date date,
    due_date date,
    deliverables jsonb
  )
), deliverable_seed as (
  select distinct
    phases.id as phase_id,
    deliverable_title as title,
    case raw_tasks.status
      when 'Completado' then 'Aprobado'
      when 'En progreso' then 'En elaboracion'
      when 'En revision' then 'En revision interna'
      when 'Bloqueado' then 'Requiere ajustes'
      else 'Pendiente'
    end as status
  from raw_tasks
  join public.phases on phases.code = raw_tasks.phase_code
  cross join lateral jsonb_array_elements_text(raw_tasks.deliverables) as deliverable_title
)
insert into public.deliverables (title, phase_id, status)
select deliverable_seed.title, deliverable_seed.phase_id, deliverable_seed.status
from deliverable_seed
where not exists (
  select 1
  from public.deliverables existing
  where lower(existing.title) = lower(deliverable_seed.title)
    and existing.phase_id = deliverable_seed.phase_id
);

