insert into public.tasks (title, description, phase_id, owner_id, status, priority, item_type, start_date, due_date, created_by)
select
  raw_tasks.title,
  raw_tasks.description,
  phases.id,
  owner_profile.id,
  raw_tasks.status::task_status,
  raw_tasks.priority::priority_level,
  raw_tasks.item_type,
  raw_tasks.start_date,
  raw_tasks.due_date,
  owner_profile.id
from raw_tasks
join public.phases on phases.code = raw_tasks.phase_code
left join public.profiles owner_profile on lower(owner_profile.full_name) = lower(raw_tasks.owner_name);

