m_type": "Entregable", "status": "No iniciado", "priority": "Alta", "owner_name": "Laura Salazar", "start_date": "2026-08-12", "due_date": "2026-08-12", "deliverables": ["Repositorio digital completo de la consultoría (accesible para el equipo de Pinares)"]}, {"phase_code": "fase-6", "title": "Presentación ejecutiva de resultados", "description": null, "item_type": "Hito", "status": "No iniciado", "priority": "Alta", "owner_name": "Laura Salazar", "start_date": "2026-08-12", "due_date": "2026-08-12", "deliverables": []}, {"phase_code": "fase-6", "title": "Acta de cierre y próximos pasos acordados", "description": null, "item_type": "Entregable", "status": "No iniciado", "priority": "Alta", "owner_name": "Laura Salazar", "start_date": "2026-08-12", "due_date": "2026-08-12", "deliverables": ["Acta de cierre y próximos pasos acordados"]}]$$::jsonb) as x(
    phase_code text,
    title text,
    description text,
    item_type text,
    status text,
    priority text,
    owner_name text,
    start_date date,
    due_date date,
    deliverables jsonb
  )
), task_lookup as (
  select tasks.id as task_id, raw_tasks.deliverables, phases.id as phase_id
  from raw_tasks
  join public.phases on phases.code = raw_tasks.phase_code
  join public.tasks on tasks.phase_id = phases.id and tasks.title = raw_tasks.title
), deliverable_lookup as (
  select task_lookup.task_id, deliverables.id as deliverable_id
  from task_lookup
  cross join lateral jsonb_array_elements_text(task_lookup.deliverables) as deliverable_title
  join public.deliverables on lower(deliverables.title) = lower(deliverable_title)
    and deliverables.phase_id = task_lookup.phase_id
)
insert into public.task_deliverables (task_id, deliverable_id)
select task_id, deliverable_id
from deliverable_lookup
on conflict do nothing;
